			function() {
				var defaultNumber = frm.doc.custom_mobile || '';
				var d = new frappe.ui.Dialog({
					title: 'Make a call',
					fields: [{ fieldtype: 'Data', fieldname: 'destination_number', label: 'Destination Number', default: defaultNumber, reqd: 1 }],
					primary_action_label: 'Call',
					primary_action: function(values) {
						var num = values.destination_number;
						if (!num) { frappe.msgprint('Please enter a destination number'); return; }
						frappe.call({
							method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.click_to_call',
							args: { destination_number: num, did_type: 'service' },
							callback: function(r) { d.hide(); showCallWidget(num, r.message, null, frappe.call); }
						});
