		);

		// ── Email Button ──────────────────────────────────────────
		frm.add_custom_button(
			'<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:middle;margin-right:4px;"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg> Email',
			function() { openEmailDialog(frm); }
		);

		// checkForActiveCalls(frappe.call);
	}
});

// ── Gmail-style Email Composer ────────────────────────────────────
