	// ── Load draft ────────────────────────────────────────────────
	function loadDraft() {
		try { var r = sessionStorage.getItem(draftKey); return r ? JSON.parse(r) : null; } catch(e) { return null; }
	}
	function saveDraft() {
		try {
			sessionStorage.setItem(draftKey, JSON.stringify({
				to:      document.getElementById('ae-to').value,
				cc:      document.getElementById('ae-cc').value,
				subject: document.getElementById('ae-subject').value,
				body:    editor.innerHTML,
				savedAt: Date.now()
			}));
		} catch(e) {}
	}
	function clearDraft() { try { sessionStorage.removeItem(draftKey); } catch(e) {} }

	var draft = loadDraft();
	if (draft && (draft.body || draft.to)) {
		if (draft.to)      document.getElementById('ae-to').value      = draft.to;
		if (draft.cc)      document.getElementById('ae-cc').value      = draft.cc;
		if (draft.subject) document.getElementById('ae-subject').value = draft.subject;
		if (draft.body)    editor.innerHTML = draft.body;
		statusBar.textContent = 'Draft restored';
		setTimeout(function() { if (statusBar.textContent === 'Draft restored') statusBar.textContent = ''; }, 2500);
	}

	editor.focus();

	function setStatus(msg, color) { statusBar.textContent = msg; statusBar.style.color = color || '#5f6368'; }

	// ── Draft auto-save on input ──────────────────────────────────
	var draftTimer = null;
	function scheduleSave() { if (draftTimer) clearTimeout(draftTimer); draftTimer = setTimeout(saveDraft, 400); }
	editor.addEventListener('input', scheduleSave);
	document.getElementById('ae-to').addEventListener('input', scheduleSave);
	document.getElementById('ae-cc').addEventListener('input', scheduleSave);
	document.getElementById('ae-subject').addEventListener('input', scheduleSave);

	// ── Close ─────────────────────────────────────────────────────
