		var ov = document.getElementById('aionion-overlay'); if (ov) ov.remove();
		var dr = document.getElementById('aionion-drop-overlay'); if (dr) dr.remove();
	}
	document.getElementById('aionion-close').onclick = closeDialog;
	document.getElementById('aionion-discard-btn').onclick = closeDialog;
	overlay.onclick = function(e) { if (e.target === overlay) closeDialog(); };

	// ── Toolbar ───────────────────────────────────────────────────
	document.getElementById('ae-font').onchange    = function() { document.execCommand('fontName', false, this.value); editor.focus(); };
	document.getElementById('ae-size').onchange    = function() { document.execCommand('fontSize', false, this.value); editor.focus(); };
	document.getElementById('ae-bold').onclick     = function() { document.execCommand('bold'); editor.focus(); };
	document.getElementById('ae-italic').onclick   = function() { document.execCommand('italic'); editor.focus(); };
	document.getElementById('ae-underline').onclick= function() { document.execCommand('underline'); editor.focus(); };
	document.getElementById('ae-strike').onclick   = function() { document.execCommand('strikeThrough'); editor.focus(); };
	document.getElementById('ae-fgcolor').oninput  = function() { document.execCommand('foreColor', false, this.value); editor.focus(); };
	document.getElementById('ae-bgcolor').oninput  = function() { document.execCommand('hiliteColor', false, this.value); editor.focus(); };
	document.getElementById('ae-ul').onclick       = function() { document.execCommand('insertUnorderedList'); editor.focus(); };
	document.getElementById('ae-ol').onclick       = function() { document.execCommand('insertOrderedList'); editor.focus(); };
	document.getElementById('ae-left').onclick     = function() { document.execCommand('justifyLeft'); editor.focus(); };
	document.getElementById('ae-center').onclick   = function() { document.execCommand('justifyCenter'); editor.focus(); };
	document.getElementById('ae-right').onclick    = function() { document.execCommand('justifyRight'); editor.focus(); };
