	// ── Attachment chips ──────────────────────────────────────────
	function iconForFile(name) {
		var ext = (name.split('.').pop() || '').toLowerCase();
		if (['jpg','jpeg','png','gif','webp','svg'].includes(ext)) return '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>';
		if (ext === 'pdf') return '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>';
		return '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21.44 11.05l-9.19 9.19a6 6 0 0 1-8.49-8.49"/></svg>';
	}

	function addChip(name, fid, state) {
		var chip = document.createElement('div');
		chip.className = 'aionion-chip' + (state === 'uploading' ? ' uploading' : '');
		if (fid) chip.setAttribute('data-fid', fid);
		chip.innerHTML = iconForFile(name)
			+ '<span style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + name + '</span>'
			+ (state === 'uploading'
				? '<span style="font-size:10px;margin-left:3px;color:#92400e;">uploading...</span>'
				: '<button class="aionion-chip-x">&times;</button>');
		if (state !== 'uploading') chip.querySelector('.aionion-chip-x').onclick = function() { chip.remove(); };
		chipsArea.appendChild(chip);
		return chip;
	}

	function markDone(chip, file, fid) {
		chip.className = 'aionion-chip';
		chip.setAttribute('data-fid', fid);
		chip.innerHTML = iconForFile(file.name)
			+ '<span style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="' + file.name + '">' + file.name + '</span>'
			+ '<button class="aionion-chip-x">&times;</button>';
		chip.querySelector('.aionion-chip-x').onclick = function() { chip.remove(); };
	}

	function markError(chip, file, reason) {
		chip.className = 'aionion-chip error';
		chip.innerHTML = iconForFile(file.name) + '<span>' + file.name + ' &mdash; ' + (reason || 'failed') + '</span><button class="aionion-chip-x">&times;</button>';
		chip.querySelector('.aionion-chip-x').onclick = function() { chip.remove(); };
	}

	function uploadFile(file) {
		var chip = addChip(file.name, null, 'uploading');
		var fd = new FormData();
		fd.append('file', file, file.name);
		fd.append('is_private', '0');
		fd.append('attached_to_doctype', 'Customer');
		fd.append('attached_to_name', frm.doc.name);
		fetch('/api/method/upload_file', {
			method: 'POST',
			headers: { 'X-Frappe-CSRF-Token': frappe.csrf_token || '' },
			body: fd
		})
		.then(function(r) { return r.json(); })
		.then(function(d) {
			var msg = d.message || {};
			var fid = msg.name || msg.file_name;
			if (fid) { markDone(chip, file, fid); }
			else { markError(chip, file, 'upload failed'); }
		})
		.catch(function() { markError(chip, file, 'network error'); });
	}

	document.getElementById('aionion-attach-btn').onclick = function() { fileInput.click(); };
	fileInput.onchange = function() {
		Array.prototype.forEach.call(fileInput.files, function(f) { uploadFile(f); });
		fileInput.value = '';
	};

	// ── Drag & Drop ───────────────────────────────────────────────
	var dropOverlay = document.getElementById('aionion-drop-overlay');
	var modal = document.getElementById('aionion-modal');
	var dragN = 0;
	modal.addEventListener('dragenter', function(e) {
		if (!e.dataTransfer || !e.dataTransfer.types.includes('Files')) return;
		e.preventDefault(); dragN++; dropOverlay.style.display = 'flex';
	});
	modal.addEventListener('dragleave', function() {
		dragN--; if (dragN <= 0) { dragN = 0; dropOverlay.style.display = 'none'; }
	});
	modal.addEventListener('dragover', function(e) {
		if (e.dataTransfer && e.dataTransfer.types.includes('Files')) e.preventDefault();
	});
	modal.addEventListener('drop', function(e) {
		e.preventDefault(); dragN = 0; dropOverlay.style.display = 'none';
		var files = e.dataTransfer && e.dataTransfer.files;
		if (!files || !files.length) return;
		Array.prototype.forEach.call(files, function(file) {
			if (file.type.startsWith('image/')) {
				var reader = new FileReader();
				reader.onload = function(ev) {
					editor.focus();
					document.execCommand('insertHTML', false, '<img src="' + ev.target.result + '" style="max-width:100%;border-radius:4px;margin:4px 0;" />');
				};
				reader.readAsDataURL(file);
			} else { uploadFile(file); }
		});
	});

	// ── Smart Paste ───────────────────────────────────────────────
	editor.addEventListener('paste', function(e) {
		var cd = e.clipboardData || window.clipboardData;
		if (!cd) return;

		// Image paste — embed inline
		var items = cd.items;
		if (items) {
			for (var i = 0; i < items.length; i++) {
				if (items[i].type.indexOf('image') !== -1) {
					e.preventDefault();
					var file = items[i].getAsFile();
					var reader = new FileReader();
					reader.onload = function(ev) {
						document.execCommand('insertHTML', false, '<img src="' + ev.target.result + '" style="max-width:100%;border-radius:4px;margin:4px 0;" />');
					};
					reader.readAsDataURL(file);
					return;
				}
			}
		}

		var htmlData = cd.getData('text/html');
		var textData = cd.getData('text/plain');

		// Excel/Sheets table paste
		if (htmlData && htmlData.toLowerCase().includes('<table')) {
			e.preventDefault();
			var parser = new DOMParser();
			var parsed = parser.parseFromString(htmlData, 'text/html');
			var tables = parsed.querySelectorAll('table');
			var result = '';
			tables.forEach(function(tbl) {
				var rows = tbl.querySelectorAll('tr');
				var isFirst = true;
				var t = '<table style="border-collapse:collapse;width:100%;margin:8px 0;">';
				rows.forEach(function(row) {
					var cells = row.querySelectorAll('td,th');
					if (!cells.length) return;
					var rowText = ''; cells.forEach(function(c) { rowText += c.innerText.trim(); });
					if (!rowText) return;
					t += '<tr>';
					cells.forEach(function(cell) {
						var tag = isFirst ? 'th' : 'td';
						var s = isFirst ? 'border:1px solid #d1d5db;padding:6px 10px;background:#f8f9fa;font-weight:600;text-align:left;' : 'border:1px solid #d1d5db;padding:6px 10px;text-align:left;';
						t += '<' + tag + ' style="' + s + '">' + (cell.innerText.trim() || '&nbsp;') + '</' + tag + '>';
					});
					t += '</tr>'; isFirst = false;
				});
				t += '</table>'; result += t;
			});
			if (result) document.execCommand('insertHTML', false, result);
			return;
		}

		// Tab-separated paste
		if (textData && textData.includes('\t') && textData.split('\n').length > 1) {
			e.preventDefault();
			var lines = textData.split('\n').map(function(l) { return l.trim(); }).filter(Boolean);
			var t = '<table style="border-collapse:collapse;width:100%;margin:8px 0;">';
			lines.forEach(function(line, i) {
				var cells = line.split('\t').map(function(c) { return c.trim(); });
				var tag = i === 0 ? 'th' : 'td';
				var s = i === 0 ? 'border:1px solid #d1d5db;padding:6px 10px;background:#f8f9fa;font-weight:600;text-align:left;' : 'border:1px solid #d1d5db;padding:6px 10px;text-align:left;';
				t += '<tr>' + cells.map(function(c) { return '<' + tag + ' style="' + s + '">' + c + '</' + tag + '>'; }).join('') + '</tr>';
			});
			t += '</table>';
			document.execCommand('insertHTML', false, t);
			return;
		}
		// Plain text / formatted web text — browser handles naturally
	});

	// ── Send ──────────────────────────────────────────────────────
	document.getElementById('aionion-send-btn').onclick = function() {
		var to      = (document.getElementById('ae-to').value || '').trim();
		var cc      = (document.getElementById('ae-cc').value || '').trim();
		var subject = (document.getElementById('ae-subject').value || '').trim();
		var html    = editor.innerHTML.trim();

		if (!to)      { setStatus('To email is required', '#c5221f'); return; }
		if (!subject) { setStatus('Subject is required', '#c5221f'); return; }
		if (!html || html === '<br>') { setStatus('Message cannot be empty', '#c5221f'); return; }

		var fids = [];
		document.querySelectorAll('.aionion-chip[data-fid]').forEach(function(chip) {
			var fid = chip.getAttribute('data-fid'); if (fid) fids.push(fid);
		});

		if (document.querySelectorAll('.aionion-chip.uploading').length > 0) {
			setStatus('Please wait — files still uploading...', '#e37400'); return;
		}

		var sendBtn = document.getElementById('aionion-send-btn');
		sendBtn.textContent = 'Sending...';
		sendBtn.disabled = true;
		setStatus('Sending...', '#5f6368');

		fetch('/api/method/crm_lead_send_email', {
			method: 'POST',
			headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'X-Frappe-CSRF-Token': frappe.csrf_token || '' },
			body: [
				'customer_name='    + encodeURIComponent(frm.doc.name),
				'recipient_emails=' + encodeURIComponent(to),
				'cc_emails='        + encodeURIComponent(cc),
				'subject='          + encodeURIComponent(subject),
				'body_html='        + encodeURIComponent(html),
				'attachment_fids='  + encodeURIComponent(fids.join(','))
			].join('&')
		})
		.then(function(r) { return r.json(); })
		.then(function(d) {
			var msg = d.message || {};
			if (msg.email_sent) {
				clearDraft();
				setStatus('Email sent!', '#188038');
				frappe.show_alert({ message: 'Email sent to ' + to, indicator: 'green' });
				setTimeout(function() { closeDialog(); }, 1500);
			} else {
				setStatus('Queued — ' + (msg.email_error || 'check email settings'), '#e37400');
				setTimeout(function() { closeDialog(); }, 3000);
			}
		})
		.catch(function(err) {
			sendBtn.textContent = 'Send';
			sendBtn.disabled = false;
			setStatus('Error: ' + (err.message || 'Unknown'), '#c5221f');
		});
	};
}

// ── Poll for incoming/active calls ────────────────────────────────
var _customerCallShownIds = new Set();
var _customerCallPollTimer = null;

function checkForActiveCalls(call) {
	if (_customerCallPollTimer) return;
	function poll() {
		if (document.getElementById('smartflo-call-widget')) return;
		frappe.call({
			method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.get_live_calls',
			args: {},
			callback: function(r) {
				var data = r.message;
				if (!data || !data.agent_number) return;
				var liveCalls = Array.isArray(data.data) ? data.data : [];
				for (var i = 0; i < liveCalls.length; i++) {
					var c = liveCalls[i];
