		// ----------------------------------------------------------------
		// CUSTOMER 360 PANEL — UNCHANGED from existing script
		// Full HTML render: Insurance, Renewals, US Subscription,
		// Bonds, Mutual Funds, Equity tables
		// ----------------------------------------------------------------
		frappe.call({
			method: 'aionion_custom.aionion_custom.controllers.customer.get_customer_360',
			args: { customer_name: frm.doc.name },
			callback: function(r) {
				if (!r.message) return;
				const data = r.message;
				const products = data.products;
				const customer = data.customer;

				let html = `<div id="customer-360-panel" style="margin:15px 0;padding:15px;border:1px solid #d1d8dd;border-radius:8px;background:#f8f9fa;">
					<div style="margin-bottom:12px">
						<h4 style="margin:0;color:#2c3e50;font-size:15px">🎯 Customer 360</h4>
						<small style="color:#888">
							Master ID: <b>${customer.aionion_master_id || 'Not assigned'}</b> |
							Mobile: ${customer.mobile || '-'} |
							PAN: ${customer.pan || '-'}
						</small>
					</div>`;

				if (products.insurance && products.insurance.length > 0) {
					html += `<div style="margin-bottom:12px">
						<b style="color:#1a73e8">🛡️ Insurance Records (${products.insurance.length})</b>
						<table style="width:100%;margin-top:6px;border-collapse:collapse;font-size:12px">
							<tr style="background:#e8f0fe;font-weight:600">
								<td style="padding:5px;border:1px solid #ddd">Record</td>
								<td style="padding:5px;border:1px solid #ddd">Type</td>
								<td style="padding:5px;border:1px solid #ddd">Policy No</td>
								<td style="padding:5px;border:1px solid #ddd">Status</td>
								<td style="padding:5px;border:1px solid #ddd">Expiry</td>
							</tr>`;
					products.insurance.forEach(p => {
						html += `<tr>
							<td style="padding:5px;border:1px solid #ddd"><a href="/desk/insurance-record/${p.name}" target="_blank">${p.name}</a></td>
							<td style="padding:5px;border:1px solid #ddd">${p.insurance_products || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.policy_number || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.policy_status || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.policy_expiry_date || '-'}</td>
						</tr>`;
					});
					html += '</table></div>';
				}

				if (products.renewals && products.renewals.length > 0) {
					html += `<div style="margin-bottom:12px">
						<b style="color:#0d7377">🔄 Renewal Records (${products.renewals.length})</b>
						<table style="width:100%;margin-top:6px;border-collapse:collapse;font-size:12px">
							<tr style="background:#e0f7f7;font-weight:600">
								<td style="padding:5px;border:1px solid #ddd">Record</td>
								<td style="padding:5px;border:1px solid #ddd">Type</td>
								<td style="padding:5px;border:1px solid #ddd">Expiry</td>
								<td style="padding:5px;border:1px solid #ddd">Status</td>
								<td style="padding:5px;border:1px solid #ddd">Renewals RM</td>
							</tr>`;
					products.renewals.forEach(p => {
						html += `<tr>
							<td style="padding:5px;border:1px solid #ddd"><a href="/desk/insurance-renewal-record/${p.name}" target="_blank">${p.name}</a></td>
							<td style="padding:5px;border:1px solid #ddd">${p.insurance_type || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.policy_expiry_date || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.renewal_status || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.renewals_rm_name || 'Not assigned'}</td>
						</tr>`;
					});
					html += '</table></div>';
				}

				if (products.us_subscription && products.us_subscription.length > 0) {
					html += `<div style="margin-bottom:12px">
						<b style="color:#6200ea">🌐 US Subscription (${products.us_subscription.length})</b>
						<table style="width:100%;margin-top:6px;border-collapse:collapse;font-size:12px">
							<tr style="background:#ede7f6;font-weight:600">
								<td style="padding:5px;border:1px solid #ddd">Record</td>
								<td style="padding:5px;border:1px solid #ddd">Status</td>
								<td style="padding:5px;border:1px solid #ddd">Amount</td>
								<td style="padding:5px;border:1px solid #ddd">End Date</td>
							</tr>`;
					products.us_subscription.forEach(p => {
						html += `<tr>
							<td style="padding:5px;border:1px solid #ddd">${p.name}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.client_status || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">₹${(p.amount_paid_us_subs || 0).toLocaleString()}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.subscription_end_date || '-'}</td>
						</tr>`;
					});
					html += '</table></div>';
				}

				if (products.bonds && products.bonds.length > 0) {
					html += `<div style="margin-bottom:12px">
						<b style="color:#2e7d32">📈 Bonds (${products.bonds.length})</b>
						<table style="width:100%;margin-top:6px;border-collapse:collapse;font-size:12px">
							<tr style="background:#e8f5e9;font-weight:600">
								<td style="padding:5px;border:1px solid #ddd">Record</td>
								<td style="padding:5px;border:1px solid #ddd">Units</td>
								<td style="padding:5px;border:1px solid #ddd">Amount</td>
								<td style="padding:5px;border:1px solid #ddd">Execution Date</td>
							</tr>`;
					products.bonds.forEach(p => {
						html += `<tr>
							<td style="padding:5px;border:1px solid #ddd">${p.name}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.number_of_units || 0}</td>
							<td style="padding:5px;border:1px solid #ddd">₹${(p.amount_bonds || 0).toLocaleString()}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.execution_date || '-'}</td>
						</tr>`;
					});
					html += '</table></div>';
				}

				if (products.mutual_funds && products.mutual_funds.length > 0) {
					html += `<div style="margin-bottom:12px">
						<b style="color:#e65100">💰 Mutual Funds (${products.mutual_funds.length})</b>
						<table style="width:100%;margin-top:6px;border-collapse:collapse;font-size:12px">
							<tr style="background:#fff3e0;font-weight:600">
								<td style="padding:5px;border:1px solid #ddd">Record</td>
								<td style="padding:5px;border:1px solid #ddd">Amount</td>
								<td style="padding:5px;border:1px solid #ddd">Order Type</td>
							</tr>`;
					products.mutual_funds.forEach(p => {
						html += `<tr>
							<td style="padding:5px;border:1px solid #ddd">${p.name}</td>
							<td style="padding:5px;border:1px solid #ddd">₹${(p.amount_mf || 0).toLocaleString()}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.order_type || '-'}</td>
						</tr>`;
					});
					html += '</table></div>';
				}

				if (products.equity && products.equity.length > 0) {
					html += `<div style="margin-bottom:12px">
						<b style="color:#880e4f">📊 Equity / Account Opening (${products.equity.length})</b>
						<table style="width:100%;margin-top:6px;border-collapse:collapse;font-size:12px">
							<tr style="background:#fce4ec;font-weight:600">
								<td style="padding:5px;border:1px solid #ddd">Record</td>
								<td style="padding:5px;border:1px solid #ddd">PAN</td>
								<td style="padding:5px;border:1px solid #ddd">Client Code</td>
							</tr>`;
					products.equity.forEach(p => {
						html += `<tr>
							<td style="padding:5px;border:1px solid #ddd">${p.name}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.pan || '-'}</td>
							<td style="padding:5px;border:1px solid #ddd">${p.client_code || '-'}</td>
						</tr>`;
					});
					html += '</table></div>';
				}

				const total = Object.values(products).reduce((a, b) => a + (b ? b.length : 0), 0);
				if (total === 0) {
					html += '<div style="text-align:center;color:#888;padding:10px">No product records found</div>';
				}
				html += '</div>';
				frm.layout.wrapper.find('.form-page').prepend($(html));
			}
		});
	}
});

frappe.ui.form.on('Insurance Renewal Record', {
    refresh(frm) {

        // ── ASSIGN RENEWALS RM (Manager only) ──
        if (frappe.user_roles.includes('Insurance Renewals Manager')) {
            frm.add_custom_button('Assign Renewals RM', () => {
                frappe.call({
                    method: 'aionion_custom.aionion_custom.controllers.crm_lead.get_renewals_rm_list_for_assign',
                    callback(r) {
                        if (!r.message || !r.message.length) {
                            frappe.msgprint('No Renewals RM available.');
                            return;
                        }
                        const rms = r.message;
                        const options = rms.map(rm => rm.employee + ' — ' + rm.name);
                        const employees = rms.map(rm => rm.employee);

                        frappe.prompt([{
                            label: 'Select Renewals RM',
                            fieldname: 'renewals_rm',
                            fieldtype: 'Select',
                            options: options.join('\n'),
                            reqd: 1
                        }], (values) => {
                            const idx = options.indexOf(values.renewals_rm);
                            const emp = employees[idx];
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.assign_renewals_rm',
                                args: { record_name: frm.doc.name, renewals_rm: emp },
                                callback(r) {
                                    if (!r.exc) {
                                        frappe.show_alert({ message: 'Assigned to ' + r.message.rm_name, indicator: 'green' });
                                        frm.reload_doc();
                                    }
                                }
                            });
                        }, 'Assign Renewals RM', 'Assign');
                    }
                });
            }, 'Actions');
        }

        // ── VERIFY RENEWAL MIS ──
        if (frappe.user_roles.includes('Insurance MIS') || frappe.user_roles.includes('Insurance Renewals Manager')) {
            if (frm.doc.mis_status !== 'Approved') {
                frm.add_custom_button('Verify Renewal MIS', () => {
                    if (!frm.doc.new_policy_number) {
                        frappe.msgprint('Please fill New Policy Number before verifying.');
                        return;
                    }
                    frappe.confirm(
                        `Confirm new policy <b>${frm.doc.new_policy_number}</b> is verified in the insurer portal?`,
                        () => {
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.approve_renewal_mis',
                                args: { record_name: frm.doc.name },
                                callback(r) {
                                    if (!r.exc) {
                                        frappe.show_alert({ message: 'Renewal MIS Verified!', indicator: 'green' });
                                        frm.reload_doc();
                                    }
                                }
                            });
                        }
                    );
                }, 'MIS Actions');
            }

            if (frm.doc.mis_status !== 'Rejected') {
                frm.add_custom_button('Reject Renewal MIS', () => {
                    frappe.prompt(
                        [{ label: 'Reason', fieldname: 'reason', fieldtype: 'Small Text' }],
                        (values) => {
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.reject_renewal_mis',
                                args: { record_name: frm.doc.name, reason: values.reason },
                                callback(r) {
                                    if (!r.exc) {
                                        frappe.show_alert({ message: 'Renewal MIS Rejected.', indicator: 'red' });
                                        frm.reload_doc();
                                    }
                                }
                            });
                        }, 'Reject Reason', 'Reject'
                    );
                }, 'MIS Actions');
            }
        }

        // Status indicators
        if (frm.doc.mis_status === 'Approved') frm.page.set_indicator('MIS Approved', 'green');
        else if (frm.doc.mis_status === 'Rejected') frm.page.set_indicator('MIS Rejected', 'red');
        else frm.page.set_indicator('Pending MIS', 'orange');

        if (frm.doc.renewal_status === 'Renewed') frm.page.set_indicator('Renewed', 'green');
        else if (frm.doc.renewal_status === 'In Progress') frm.page.set_indicator('In Progress', 'blue');
    }
});
